import type { SyntaxNodeRef, TreeCursor } from '@lezer/common';

import type { ConvertedLezerNode } from '../../../../types/conversion-utils.js';
import type { FilterFieldErrorNode } from '../../../../types/tree-nodes.js';
import { getTextFromRange } from '../../../get-text.js';
import { updateNodeValues } from '../node-mutations.js';

/**
 * Convert an error node, including all directly following errors.
 * Needs the parentCursor to move the cursor to the last consecutive error node to avoid duplicate conversion.
 * @internal
 */
export function convertError(
  parentCursor: TreeCursor,
  node: SyntaxNodeRef,
  doc: string,
): ConvertedLezerNode<FilterFieldErrorNode> {
  const { from, to } = node;
  const cursor = node.node.cursor();

  const convertedNode: FilterFieldErrorNode = {
    type: 'Error',
    textValue: '',
    value: '',
    range: { from, to },
  };

  let hasNextSibling = cursor.nextSibling();
  // Combine all consecutive errors into one node.
  while (hasNextSibling && cursor.node.name === '⚠') {
    convertedNode.range.to = cursor.node.to;
    hasNextSibling = cursor.nextSibling();
  }

  // Move back to the last error node (else, the next sibling would be skipped).
  // If the last error node is also the last node in the lezer tree, the cursor is still at this node.
  if (hasNextSibling) {
    cursor.prevSibling();
  }

  const textValue = getTextFromRange(convertedNode.range, doc);
  updateNodeValues(convertedNode, textValue);

  // Move the parent cursor to the last error node so we don't convert nodes twice.
  // The side is set to '-1' so we don't end up at the 'Filter' node, but at the inner nodes.
  // If the last node in the lezer tree is an error node not spanning at least one character,
  // we need to advance the cursor once to get to the error.
  /*
    E.g.: foo !
    Filter [tree="fresh"]<0,5> {
      FilterStatement<0,5> {
        FilterKey<0,3> {
          Identifier<0,3>
        }
        InvalidComparisonOperator<4,5> <-- Moving the cursor to cursor.node.to -1, we'll end up here.
        ⚠<5,5>
      }
    }
  */
  if (parentCursor.node.to < cursor.node.to) {
    parentCursor.moveTo(cursor.node.to, -1);
  }

  if (
    parentCursor.node.to === cursor.node.to &&
    (cursor.nextSibling() || cursor.node.name === '⚠') &&
    cursor.node.from === cursor.node.to
  ) {
    parentCursor.nextSibling();
  }

  return { convertedNode, errors: [] };
}
